queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?room_type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasRooms ?child ; p:hasBed_and_breakfast ?parent . } GROUP BY ?child }
  ?child p:room_type ?room_type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Bed_and_breakfast } }
  FILTER(?nf = ?total)
}

